        const event = events[i];

        // Stopping condition check before processing the current event
        if (counter === 10) {
            break;
        }

        if (event === "0" || event === "1" || event === "2" || event === "3" || event === "4" || event === "6") {
            // Numerical events add their value to the score
            switch (event) {
                case "0": score += 0; break;
                case "1": score += 1; break;
                case "2": score += 2; break;
                case "3": score += 3; break;
                case "4": score += 4; break;
                case "6": score += 6; break;
            }
        } else if (event === "W") {
            // "W": counter increases by 1, score does not change
            counter += 1;
        } else if (event === "WD") {
            // "WD": total score increases by 1
            score += 1;
        } else if (event === "NB") {
            // "NB": total score increases by 1
            score += 1;
        }
    }

    // Final check for the stopping condition after the loop, if it stopped because counter reached 10 *after* processing the last event.
    // The loop condition already handles stopping *before* processing if counter was 10 at the start of the iteration.
    // If the loop finishes naturally (i.e., all events are processed), we return the current state.

    return [score, counter];
}

