    long long score = 0;
    long long counter = 0;

    for (size_t i = 0; i < events.size(); ++i) {
        const std::string& event = events[i];

        // Stopping condition check: if counter reaches 10, stop processing *before* the current event.
        // Note: The provided JS reference checks this at the start of the loop iteration.
        // If counter became 10 on the *previous* iteration, we break here.
        if (counter == 10) {
            break;
        }

        if (event == "0" || event == "1" || event == "2" || event == "3" || event == "4" || event == "6") {
            // Numerical events add their value to the score
            if (event == "0") score += 0;
            else if (event == "1") score += 1;
            else if (event == "2") score += 2;
            else if (event == "3") score += 3;
            else if (event == "4") score += 4;
            else if (event == "6") score += 6;
        } else if (event == "W") {
            // "W": counter increases by 1, score does not change
            counter += 1;
        } else if (event == "WD") {
            // "WD": total score increases by 1
            score += 1;
        } else if (event == "NB") {
            // "NB": total score increases by 1
            score += 1;
        }

        // Crucial check based on Example 3: If the current event caused counter to become 10, 
        // we must stop immediately after processing it, preventing the next iteration from running.
        if (event == "W" && counter == 10) {
            break;
        }
    }

    // If the loop finished because all events were processed, the final score/counter is correct.
    // If it stopped because counter reached 10, the final score/counter reflects the state after the last processed event.

    return {score, counter};
}

